// Extract event data from router payload
const input = $input.first().json;

const eventId = input.body?.event_id || input.event_id;
const projectId = input.body?.project_id || input.project_id;
const payload = input.body?.payload || input.payload || {};

const stepKey = `material_list:${projectId}`;

return {
  json: {
    event_id: eventId,
    project_id: projectId,
    step_key: stepKey,
    payload: payload
  }
};

// ============================================================
// Step 4+5: CALCULATE QUANTITIES + CONSOLIDATE
// ============================================================

const positions = $('Load Positions').all().map(i => i.json);
const rooms = $('Load Room Measurements').all().map(i => i.json);
const mappings = $('Load Material Mappings').all().map(i => i.json);
const eventData = $('Parse Event Data').first().json;

// Build room lookup by measurement_id and by room_name (fuzzy)
const roomById = {};
const roomByName = {};
for (const r of rooms) {
  roomById[r.id] = r;
  // Normalize room name for matching
  const normName = r.room_name.toLowerCase().replace(/\s+\d+$/, '').trim();
  roomByName[normName] = r;
  roomByName[r.room_name.toLowerCase().trim()] = r;
}

// Build mapping lookup: catalog_code → [mappings]
const mappingLookup = {};
for (const m of mappings) {
  const key = m.catalog_position_nr;
  if (!mappingLookup[key]) mappingLookup[key] = [];
  mappingLookup[key].push(m);
}

// Project info from first position
const projectInfo = positions.length > 0 ? {
  project_number: positions[0].project_number,
  project_name: positions[0].project_name,
  object_street: positions[0].object_street
} : { project_number: 'N/A', project_name: 'N/A', object_street: 'N/A' };

// Detail: per-room, per-position material lines
const detail = [];
// Track unmatched positions
const unmatchedPositions = new Set();

for (const pos of positions) {
  // Try matching catalog_code to mappings
  const catalogCode = (pos.catalog_code || '').trim();
  const materialMappings = mappingLookup[catalogCode] || [];

  if (materialMappings.length === 0) {
    unmatchedPositions.add(catalogCode || `pos_${pos.position_number}`);
    continue;
  }

  // Find room for this position
  let room = null;
  if (pos.room_measurement_id) {
    room = roomById[pos.room_measurement_id];
  }
  if (!room && pos.room_name) {
    const normRoomName = pos.room_name.toLowerCase().replace(/\s+\d+$/, '').trim();
    room = roomByName[pos.room_name.toLowerCase().trim()] || roomByName[normRoomName];
  }

  for (const mapping of materialMappings) {
    let finalQty;

    if (!mapping.multiplier_field) {
      // Fixed quantity
      finalQty = mapping.default_qty * mapping.multiplier_factor;
    } else if (mapping.multiplier_field === 'position_qty') {
      finalQty = (pos.quantity || 1) * mapping.default_qty * mapping.multiplier_factor;
    } else {
      // Room-area-based: floor_area_m2, wall_area_m2, room_perimeter_m, ceiling_area_m2
      const areaValue = room ? (parseFloat(room[mapping.multiplier_field]) || 0) : 0;
      finalQty = areaValue * mapping.default_qty * mapping.multiplier_factor;
    }

    // Round up to sensible units
    if (['Sack', 'Eimer', 'Kanister', 'Dose'].includes(mapping.unit)) {
      finalQty = Math.ceil(finalQty);
    } else if (['St', 'Set'].includes(mapping.unit)) {
      finalQty = Math.ceil(finalQty);
    } else {
      finalQty = Math.round(finalQty * 100) / 100; // 2 decimals for m², lfm, kg
    }

    if (finalQty > 0) {
      detail.push({
        room: pos.room_name || 'Allgemein',
        position_nr: catalogCode,
        material_name: mapping.material_name,
        qty: finalQty,
        unit: mapping.unit,
        gewerk: mapping.gewerk,
        product_pool_id: mapping.product_pool_id || null,
        note: mapping.note || null
      });
    }
  }
}

// Step 5: CONSOLIDATE — group by (material_name + unit + gewerk)
const consolidated = {};
for (const d of detail) {
  const key = `${d.gewerk}||${d.material_name}||${d.unit}`;
  if (!consolidated[key]) {
    consolidated[key] = {
      gewerk: d.gewerk,
      material_name: d.material_name,
      total_qty: 0,
      unit: d.unit,
      rooms: new Set(),
      product_pool_id: d.product_pool_id
    };
  }
  consolidated[key].total_qty += d.qty;
  consolidated[key].rooms.add(d.room);
}

// Convert to array, round totals
const consolidatedArr = Object.values(consolidated).map(c => ({
  gewerk: c.gewerk,
  material_name: c.material_name,
  total_qty: ['Sack', 'Eimer', 'Kanister', 'Dose', 'St', 'Set'].includes(c.unit)
    ? Math.ceil(c.total_qty)
    : Math.round(c.total_qty * 100) / 100,
  unit: c.unit,
  rooms: Array.from(c.rooms),
  product_pool_id: c.product_pool_id
})).sort((a, b) => a.gewerk.localeCompare(b.gewerk) || a.material_name.localeCompare(b.material_name));

// Stats
const gewerke = [...new Set(consolidatedArr.map(c => c.gewerk))];
const totalItems = consolidatedArr.length;
const totalGewerke = gewerke.length;
const roomNames = [...new Set(detail.map(d => d.room))];

return {
  json: {
    project_id: eventData.project_id,
    step_key: eventData.step_key,
    event_id: eventData.event_id,
    project_number: projectInfo.project_number,
    project_name: projectInfo.project_name,
    object_street: projectInfo.object_street,
    detail: detail,
    consolidated: consolidatedArr,
    stats: {
      total_items: totalItems,
      total_gewerke: totalGewerke,
      total_detail_lines: detail.length,
      gewerke: gewerke,
      rooms: roomNames,
      unmatched_positions: Array.from(unmatchedPositions)
    }
  }
};

// Step 6: Build SQL for UPSERT into project_material_needs
// Using detail rows (per-room) with ON CONFLICT idempotency
const data = $input.first().json;
const detail = data.detail;
const projectId = data.project_id;

if (detail.length === 0) {
  return { json: { sql: '-- No materials to write', rows_affected: 0, ...data } };
}

// Build VALUES clause
const valueRows = detail.map(d => {
  const label = d.material_name.replace(/'/g, "''");
  const room = (d.room || 'Allgemein').replace(/'/g, "''");
  const gewerk = d.gewerk.replace(/'/g, "''");
  const note = d.note ? d.note.replace(/'/g, "''") : null;
  const posNr = d.position_nr.replace(/'/g, "''");
  const productId = d.product_pool_id ? `'${d.product_pool_id}'::uuid` : 'NULL';

  return `(
    '${projectId}'::uuid,
    '${room}',
    '${gewerk}',
    '${gewerk}',
    '${label}',
    ${d.qty},
    '${d.unit}',
    ${productId},
    '${posNr}',
    'planned',
    'auto'
  )`;
}).join(',\n');

const sql = `INSERT INTO project_material_needs (
  project_id, room, trade, material_type, label,
  total_quantity, quantity_unit, product_id,
  source_position_nr, status, source
) VALUES
${valueRows}
ON CONFLICT (project_id, label, COALESCE(room, '__all__'))
DO UPDATE SET
  total_quantity = EXCLUDED.total_quantity,
  trade = EXCLUDED.trade,
  source_position_nr = EXCLUDED.source_position_nr,
  updated_at = now()
RETURNING id;`;

return { json: { sql, ...data } };

// Merge write result with calculation data
const writeResult = $input.all().map(i => i.json);
const calcData = $('Calculate + Consolidate').first().json;

return {
  json: {
    ...calcData,
    rows_written: writeResult.length
  }
};

const data = $('Merge Write Result').first().json;
return {
  json: {
    success: true,
    project_id: data.project_id,
    total_items: data.stats.total_items,
    total_gewerke: data.stats.total_gewerke,
    total_detail_lines: data.stats.total_detail_lines,
    rows_written: data.rows_written,
    unmatched_positions: data.stats.unmatched_positions
  }
};

// Step already done or in progress by another run
const claimResult = $input.first().json;
const eventData = $('Parse Event Data').first().json;

if (claimResult.current_status === 'DONE') {
  return {
    json: {
      status: 'skipped',
      reason: 'Material list already generated for this project',
      current_status: claimResult.current_status,
      project_id: eventData.project_id
    }
  };
}

return {
  json: {
    status: 'skipped',
    reason: 'Step in progress by another run',
    current_status: claimResult.current_status
  }
};

